import { writeFile } from 'node:fs/promises';
import { resolve } from 'node:path';
import fs from 'fs-extra';
import { simpleGit } from 'simple-git';
import { loadBrowserConfig } from './config/load.js';
import { firefoxCompatibility } from './firefox/compatibility.js';
import { generateMozconfig } from './firefox/mozconfig.js';
import { runMach } from './mach.js';
import { prepareProject } from './prepare.js';
import { projectPaths } from './project.js';
import { downloadFirefox, latestFirefoxVersion, readFirefoxLock } from './source.js';
const { pathExists } = fs;
export async function setupProject(cwd = process.cwd(), options = {}) {
    if (!['linux', 'darwin', 'win32'].includes(process.platform)) {
        throw new Error(`GeckoKit does not support ${process.platform}. Use Linux, macOS, or Windows.`);
    }
    const config = await loadBrowserConfig(cwd);
    const locked = await readFirefoxLock(cwd).catch(() => undefined);
    const version = options.version ?? locked?.version ?? (config.firefox.version === 'latest'
        ? await latestFirefoxVersion(fetch, config.firefox.channel)
        : config.firefox.version);
    const compatibility = firefoxCompatibility(version);
    const paths = await projectPaths(cwd);
    let lock;
    if (await pathExists(paths.firefoxSource)) {
        if (!locked)
            throw new Error('Firefox source exists without geckokit.lock.json. Move it aside and run setup again.');
        if (version !== locked.version) {
            throw new Error(`Firefox ${locked.version} is locked; remove source and lockfile to select ${version}.`);
        }
        const revision = (await simpleGit(paths.firefoxSource).revparse(['HEAD'])).trim();
        if (revision !== locked.revision) {
            throw new Error(`Firefox checkout is ${revision}; lock requires ${locked.revision}. Restore the locked checkout.`);
        }
        lock = locked;
    }
    else {
        lock = await downloadFirefox(cwd, version, options.repository);
    }
    await writeFile(resolve(cwd, 'mozconfig'), generateMozconfig(config, lock.version));
    const bootstrap = await runMach([
        'bootstrap',
        '--application-choice',
        compatibility.bootstrap[config.build.mode],
    ], cwd);
    if (bootstrap !== 0)
        throw new Error(`Firefox bootstrap failed with exit code ${bootstrap}`);
    await prepareProject(cwd);
    return lock;
}
